// validateIPAddr checks if an IP address is in a private/internal range
func validateIPAddr(ip net.IP) error {
	if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
