	}

	// Create context with timeout
	ctxWithTimeout, cancel := context.WithTimeout(ctx.Request().Context(), 3*time.Second)
	defer cancel()

	// Fetch the URL content
	httpReq, err := http.NewRequestWithContext(ctxWithTimeout, "GET", req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{
			"error": "Invalid URL",
		})
	}

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{
			"error": "Failed to fetch URL",
		})
	}
	defer resp.Body.Close()

	// Check response status
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{
			"error": "Failed to fetch URL content",
		})
	}

	// Parse HTML to extract title and description
	title, description := parseHTML(resp.Body)

	// Return response
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTML extracts title and meta description from HTML content
func parseHTML(body io.Reader) (string, string) {
	doc, err := html.Parse(body)
	if err != nil {
		return "", ""
	}

	var title, description string
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil {
				title = strings.TrimSpace(n.FirstChild.Data)
			}

			// Extract meta description
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name != "" {
					description = strings.TrimSpace(content)
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}

	f(doc)
	return title, description
}

func main() {
	e := echo.New()

	// Register the preview endpoint
	e.POST("/preview", FetchURLPreview)

	// Start the server
	e.Logger.Fatal(e.Start(":8080"))
}

