	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; GoURLPreview/1.0)")

	// Execute request
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL"})
	}

	// Parse HTML content
	title, description := parseHTML(resp.Body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// parseHTML extracts the title and meta description from the HTML body.
func parseHTML(body io.Reader) (string, string) {
	tokenizer := html.NewTokenizer(body)
	var title, description string
	var inTitle bool

	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			return title, description
		case html.StartTagToken, html.SelfClosingTagToken:
			token := tokenizer.Token()
			if token.Data == "title" {
				inTitle = true
			} else if token.Data == "meta" {
				var name, content, property string
				for _, attr := range token.Attr {
					switch strings.ToLower(attr.Key) {
					case "name":
						name = strings.ToLower(attr.Val)
					case "content":
						content = attr.Val
					case "property":
						property = strings.ToLower(attr.Val)
					}
				}
				if name == "description" || property == "og:description" {
					description = content
				}
			}
		case html.TextToken:
			if inTitle {
				title = strings.TrimSpace(tokenizer.Token().Data)
				inTitle = false
			}
		}
	}
}

