		}
		// 127.0.0.0/8
		if ip4[0] == 127 {
			return true
		}
		// 0.0.0.0
		if ip4[0] == 0 {
			return true
		}
	}

	// IPv6 loopback
	if ip.IsLoopback() {
		return true
	}

	return false
}

