// parseHTML extracts title and meta description from HTML
func parseHTML(r io.Reader) (title, description string) {
	tokenizer := html.NewTokenizer(r)

	for {
		tokenType := tokenizer.Next()
		if tokenType == html.ErrorToken {
			break
		}

		token := tokenizer.Token()

		switch tokenType {
		case html.StartTagToken, html.SelfClosingTagToken:
			switch token.Data {
			case "title":
				// Get title text
				if tokenizer.Next() == html.TextToken {
					title = strings.TrimSpace(tokenizer.Token().Data)
				}
			case "meta":
				// Check for description meta tag
				var name, content string
				for _, attr := range token.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" {
					description = content
				}
			}
		}

		// Stop after finding both title and description
		if title != "" && description != "" {
			break
		}
	}

	return title, description
}

func main() {
	e := echo.New()

	// Register the preview endpoint
	e.POST("/preview", FetchURLPreview)

	// Start server
	if err := e.Start(":8080"); err != nil {
		fmt.Printf("Failed to start server: %v\n", err)
	}
}

