// ErrorResponse represents an error response
type ErrorResponse struct {
	Error string `json:"error"`
}

// FetchURLPreview handles POST requests to /preview endpoint
// It fetches the provided URL, parses HTML to extract title and meta description
func FetchURLPreview(ctx echo.Context) error {
	// Parse request body
	var req PreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{Error: "Invalid request body"})
	}

	// Validate URL
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{Error: "URL is required"})
	}

	// Create HTTP client with 3 second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create request with context for timeout control
	httpReq, err := http.NewRequestWithContext(context.Background(), http.MethodGet, req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{Error: fmt.Sprintf("Invalid URL: %v", err)})
	}

	// Set User-Agent header to avoid being blocked
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	// Fetch the URL
	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{Error: fmt.Sprintf("Failed to fetch URL: %v", err)})
	}
	defer resp.Body.Close()

	// Check response status
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{Error: fmt.Sprintf("Failed to fetch URL: status %d", resp.StatusCode)})
	}

	// Read the response body (limit to 1MB to prevent memory issues)
	body, err := io.ReadAll(io.LimitReader(resp.Body, 1024*1024))
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{Error: fmt.Sprintf("Failed to read response: %v", err)})
	}

	// Parse HTML
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return ctx.JSON(http.StatusBadRequest, ErrorResponse{Error: fmt.Sprintf("Failed to parse HTML: %v", err)})
	}

	// Extract title and description
	title := extractTitle(doc)
	description := extractMetaDescription(doc)

	// Return response
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
		URL:         req.URL,
	})
}

// extractTitle traverses the HTML tree to find the title element
func extractTitle(n *html.Node) string {
	var title string
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "title" {
			if n.FirstChild != nil {
				title = n.FirstChild.Data
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(n)
	return strings.TrimSpace(title)
}

// extractMetaDescription traverses the HTML tree to find the meta description
func extractMetaDescription(n *html.Node) string {
	var description string
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode && n.Data == "meta" {
			var name, content string
			for _, attr := range n.Attr {
				if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
					name = attr.Val
				}
				if attr.Key == "content" {
					content = attr.Val
				}
			}
			if name != "" && content != "" {
				description = content
				return
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(n)
	return strings.TrimSpace(description)
}

