		Timeout: 3 * time.Second,
	}

	// Fetch the URL content
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "failed to fetch url"})
	}
	defer resp.Body.Close()

	// Check response status
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "failed to fetch url"})
	}

	// Parse HTML to extract title and description
	title, description := extractMetaInfo(resp.Body)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractMetaInfo parses HTML and extracts title and meta description
func extractMetaInfo(body io.Reader) (string, string) {
	tokenizer := html.NewTokenizer(body)
	var title, description string
	var inTitle bool
	var titleBuffer strings.Builder

	for {
		tt := tokenizer.Next()
		if tt == html.ErrorToken {
			break
		}

		token := tokenizer.Token()

		if tt == html.StartTagToken {
			switch token.Data {
			case "title":
				inTitle = true
			case "meta":
				var name, content, property string
				for _, attr := range token.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "content":
						content = attr.Val
					case "property":
						property = attr.Val
					}
				}
				if name == "description" || property == "og:description" {
					description = content
				}
			}
		}

		if inTitle && tt == html.TextToken {
			titleBuffer.WriteString(token.Data)
		}

		if tt == html.EndTagToken && token.Data == "title" {
			inTitle = false
			title = strings.TrimSpace(titleBuffer.String())
		}
	}

	return title, description
}

func main() {
	e := echo.New()
	// Register the handler under /preview path
	e.POST("/preview", FetchURLPreview)
	// Start the server
	e.Logger.Fatal(e.Start(":8080"))
}

