)

type URLPreviewRequest struct {
	URL string `json:"url"`
}

type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func FetchURLPreview(ctx echo.Context) error {
	var req URLPreviewRequest
	if err := ctx.Bind(&req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Create HTTP client with 3 second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Create context with timeout
	reqCtx, cancel := context.WithTimeout(ctx.Request().Context(), 3*time.Second)
	defer cancel()

	// Fetch the URL
	httpReq, err := http.NewRequestWithContext(reqCtx, "GET", req.URL, nil)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to create request"})
	}

	resp, err := client.Do(httpReq)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Read the HTML content
	htmlContent, err := io.ReadAll(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to read content"})
	}

	// Parse HTML to extract title and description
	title, description := parseHTML(htmlContent)

	response := URLPreviewResponse{
		Title:       title,
		Description: description,
	}

	return ctx.JSON(http.StatusOK, response)
}

func parseHTML(htmlContent []byte) (string, string) {
	doc, err := html.Parse(strings.NewReader(string(htmlContent)))
	if err != nil {
		return "", ""
	}

	var title, description string
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title from <title> tag
			if n.Data == "title" && n.FirstChild != nil {
				title = strings.TrimSpace(n.FirstChild.Data)
			}

			// Extract meta description
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name != "" {
					description = strings.TrimSpace(content)
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}

	f(doc)
	return title, description
}

func main() {
	e := echo.New()
	e.POST("/preview", FetchURLPreview)
	e.Start(":8080")
}

