)

// PreviewRequest defines the expected JSON body structure.
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse defines the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

// FetchURLPreview handles the POST request to fetch URL metadata.
func FetchURLPreview(ctx echo.Context) error {
	// Bind the JSON body to the request struct
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	// Validate URL presence
	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Validate URL scheme to prevent SSRF to non-http(s) resources
	parsedURL, err := url.Parse(req.URL)
	if err != nil || (parsedURL.Scheme != "http" && parsedURL.Scheme != "https") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL scheme"})
	}

	// Create HTTP client with 3 seconds timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the URL content
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Check for successful status code
	if resp.StatusCode != http.StatusOK {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Non-OK status code received"})
	}

	// Parse the HTML content
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML"})
	}

	// Extract title and description
	title, description := extractMetadata(doc)

	// Return the result
	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractMetadata traverses the HTML node tree to find title and meta description.
func extractMetadata(n *html.Node) (string, string) {
	var title, description string
	var foundTitle, foundDesc bool

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && !foundTitle {
				if n.FirstChild != nil {
					title = strings.TrimSpace(n.FirstChild.Data)
					foundTitle = true
				}
			}
			// Extract Meta Description
			if n.Data == "meta" && !foundDesc {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name != "" {
					description = content
					foundDesc = true
				}
			}
		}

		// Continue traversal if either title or description is not found
		if !foundTitle || !foundDesc {
			for c := n.FirstChild; c != nil; c = c.NextSibling {
				traverse(c)
			}
		}
	}

	traverse(n)
	return title, description
}

