// FetchURLPreview handles the POST request to fetch URL preview information.
// It expects a JSON body with a "url" field.
// It fetches the content with a 3-second timeout, parses the HTML, and returns the title and meta description.
func FetchURLPreview(ctx echo.Context) error {
	req := new(PreviewRequest)
	if err := ctx.Bind(req); err != nil {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
	}

	if req.URL == "" {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "URL is required"})
	}

	// Validate URL scheme to ensure it is http or https
	parsedURL, err := url.Parse(req.URL)
	if err != nil || (parsedURL.Scheme != "http" && parsedURL.Scheme != "https") {
		return ctx.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid URL scheme"})
	}

	// Create HTTP client with 3 seconds timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Fetch the URL content
	resp, err := client.Get(req.URL)
	if err != nil {
		return ctx.JSON(http.StatusBadGateway, map[string]string{"error": "Failed to fetch URL"})
	}
	defer resp.Body.Close()

	// Parse the HTML content
	doc, err := html.Parse(resp.Body)
	if err != nil {
		return ctx.JSON(http.StatusInternalServerError, map[string]string{"error": "Failed to parse HTML"})
	}

	// Extract title and meta description
	title, description := extractMetaInfo(doc)

	return ctx.JSON(http.StatusOK, PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// extractMetaInfo traverses the HTML node tree to find the title and meta description.
func extractMetaInfo(n *html.Node) (string, string) {
	var title, description string
	var traverse func(*html.Node)

	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil {
				title = strings.TrimSpace(n.FirstChild.Data)
			}
